const { exec } = require('child_process');

// Function to execute shell command
function execShellCommand(cmd) {
  return new Promise((resolve, reject) => {
    exec(cmd, (error, stdout, stderr) => {
      if (error) {
        console.warn(`Error: ${error}`);
        reject();
        return;
      }
      resolve(stdout ? stdout : stderr);
    });
  });
}

// Main function to build and deploy application
async function main() {
  try {
    // Install dependencies
    console.log('Installing dependencies...');
    await execShellCommand('npm install');
    
    // Run tests
    console.log('Running tests...');
    await execShellCommand('npm test');

    // Build the application
    console.log('Building the application...');
    await execShellCommand('npm run build');

    // Deploy to production
    console.log('Deploying to production...');
    await execShellCommand('npm run deploy:production');
    
    console.log('Application deployed successfully!');
  } catch (error) {
    console.warn('Failed to build and deploy application', error);
  }
}

main();